var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"휴우. 멀리도 왔네.","JPN":"ふう。ずいぶん遠くまで来たね。","ENG":"Phew... This should be far enough.","TWN":"呼，飛很遠了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"잠깐 쉬자. 이제는 더 못 날겠어.","JPN":"ちょっと休もう。もう飛べない。","ENG":"Let's rest a little here. I don't think I can fly anymore right now.","TWN":"休息一下吧，我飛不動了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그 냉기 풀풀 날리던 녀석도 여기까지 쫓아오려면 쉽지 않을 거야.","JPN":"あの冷気をがんがん出してたやつも、ここまではそう簡単に追ってこれないはず。","ENG":"Plus, it won't be easy for the icy monster to follow us all the way over to here.","TWN":"那個渾身充滿寒氣的傢伙，想追到這裡應該也沒那麼容易。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저…… 도와 주셔서 감사합니다. 덕분에 부학회장님이 무사하실 수 있었어요.","JPN":"あの……助けていただいてありがとうございます。おかげさまで副学会長様がご無事でした。","ENG":"Uh... Thank you for helping us. Thanks to you, Vice President is safe.","TWN":"那個……謝謝你幫我們。多虧了你，副學會長才能平安脫險。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신, 루나라고 했죠? 그 괴물에게서 어떻게 살아나온 거예요?","JPN":"あなた、ルナといいましたわね。あの怪物からどうやって生き延びたのですか？","ENG":"You. Your name was Luna, correct? Did you not die to that monster moments before?","TWN":"你，叫露娜對吧？你是怎麼從那個怪物手裡活下來的？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭐야, 너 내가 진짜 그냥 평범한 꼬맹인 줄 알았어?","JPN":"なんだよ。あんた、アタシのこと本当にただのガキだと思ってたわけ？","ENG":"Huh? Did you think I was some normie kid?","TWN":"什麼嘛，你以為我真的就是個普通的小鬼嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……그럼 아닌가요?","JPN":"……そうではなかったのですか？","ENG":"...Are you not?","TWN":"……不是嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"당연히 아니지. 난 네가 태어나기 훨씬 전부터 살아 온 그림자거든.","JPN":"当たり前じゃん。アタシはあんたが生まれるずっと前から生きてきたシャドウなんだから。","ENG":"Of course not! I'm a Shadow who's been living way before you were even born.","TWN":"當然不是。我是你還沒出生之前，就活了很久的暗影。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그림자요?","JPN":"シャドウ？","ENG":"A Shadow?","TWN":"暗影？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 말은… 당신이 인간 흉내를 내는 침식체라고요?","JPN":"つまり……あなたは人間のふりをした侵食体ということですの？","ENG":"Does that mean... You are a C.O. that mimics humans?","TWN":"你的意思是……你是模仿人類的侵蝕體？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그래. 여기 내 목에 새겨진 문신이 그 증거야.","JPN":"そう。この首に刻まれたタトゥーがその証拠。","ENG":"Yup. And this tattoo on my neck is the proof.","TWN":"是的。我脖子上的紋身就是證據。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"핵만 멀쩡하면 아무리 베이고 박살나도 다시 살아날 수 있지.","JPN":"核さえ無事ならいくら斬られて壊されても再生することができるんだ。","ENG":"I'll be able to resurrect if my core remains intact, no matter how brutally I was crushed.","TWN":"只要核心沒事，就算再怎麼被砍斷、砸碎，我也能復活。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"와, 와, 와아…… 그림자는 처음 봤어요. 정말 사람이랑 똑같네요.","JPN":"わ、わ、わあ……シャドウなんて初めてです。本当に人間そっくりですね。","ENG":"W-wow... I've never met a Shadow before... You really do look exactly like us.","TWN":"哇，哇，哇啊……我還是第一次看到暗影。真的跟人一模一樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"크크큭, 이것도 다 오래 살아남은 덕분 아니겠어?","JPN":"くくく、それもこれも長く生きてきたおかげってやつ？","ENG":"Kekeke... It's all thanks to being alive all this time, no?","TWN":"呵呵呵，這也都是因為活了更久的緣故吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋은 정보 감사합니다. 어서 관리국에 신고해야겠네요.","JPN":"有益な情報をありがとうございます。早く管理局に通報しなければ。","ENG":"Thank you for that information. I should now report you to the Administration.","TWN":"謝謝你的情報。我要馬上向管理局報告。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그림자 정도의 침식체라면 가만히 있어도 침식파를 퍼뜨리니까요. 늦기 전에 대처해야죠.","JPN":"シャドウほどの侵食体ならば、そこに居るだけでも侵食波をまき散らします。手遅れになる前に対処しなければいけませんからね。","ENG":"A Shadow emits Corruption ray even if it stays idle. We must deal with you before it is too late.","TWN":"因為暗影這類的侵蝕體，哪怕什麼都不做也會釋放侵蝕波。必須趁早處理掉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그렇구나…. 역시 박식하세요, 부학회장님.","JPN":"そうなんですね……さすがによくご存じです、副学会長様。","ENG":"I see... You're very knowledgeable, ma'am?","TWN":"這樣啊……你果然很博學，副學會長。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"어? 어라?","JPN":"え？　ええ？","ENG":"H-huh?","TWN":"呃？咦？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"안 돼! 어딜 가! 못 가!","JPN":"ダメだよ！　どこ行くんってんだよ！　行かせないよ！","ENG":"Nuh-uh! Where do you think you're going?!","TWN":"不行！你要去哪！你不能走！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 이래요? 이거 놔요! 침식체면 침식체답게 태스크포스에 격퇴당하라고요!","JPN":"何なのですか？　放してください！　侵食体なら侵食体らしく、タスクフォースに撃退されなさい！","ENG":"What is the meaning of this?! Let go! Accept your fate as a C.O. and get exterminated by the TASKFORCE!","TWN":"你幹嘛？放開我！侵蝕體就要有個侵蝕體的樣子，就該等著被特遣勢力擊退！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"난 네 생명의 은인이라고! 그 무지막지한 놈들에게 날 팔아치울 셈이야?!","JPN":"アタシはあんたの命の恩人だよ！　あの恐ろしいやつらにアタシを売り飛ばすつもり！？","ENG":"Hey! I just saved your life! And you're going to sell me out like that?!","TWN":"我是你的救命恩人！你想把我出賣給那些愚蠢的傢伙嗎？！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아까 몸을 재생하느라 힘을 잔뜩 써 버렸단 말이야! 지금 잡히면 끝장이야!","JPN":"さっき体を再生するのにどれだけ力を使ったと思ってるんだ！　今捕まったらおしまいだよ！","ENG":"I used up all my strength recovering my body! If they catch me now, I'm toast!","TWN":"剛才為了讓身體重生，我的力氣都用光了！現在被抓到就完蛋了！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으아아아앙! 싫어 싫어! 난 오래오래 살고 싶다구! 크으응!!","JPN":"うわああああん！　やだやだ～！　もっともっと長生きしたいのにい！　ちーん！！","ENG":"WAAAAAH! NO! I don't wanna die! I wanna live forever and ever! Hngh...!","TWN":"呃啊啊啊啊！不要，不要！我還想活很久呢！嗚嗚嗚！！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 제 치마에 코를 푸는데요?!","JPN":"私のスカートで鼻をかまないでください！！","ENG":"Did you just use my skirt to blow your nose?!","TWN":"你為什麼用我的裙子擦鼻涕？！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아앗. 어떡해, 여기서는 빨래도 못 하는데….","JPN":"ああっ。どうしよう、ここでは洗濯もできないのに……","ENG":"Oh no...! We can't even do laundry here...","TWN":"啊啊，怎麼辦，這裡也不能洗衣服……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 맥크레디 양. 잠시 기다려 주게나.","JPN":"コホン、マクレディー君。ちょっと待ってくれたまえ。","ENG":"Ahem. Regina? Let's not jump to any conclusions.","TWN":"咳呵，麥克蕾蒂，請等一下。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저 아이가 그림자라고 해도, 꼭 지금 당장 격퇴할 필요는 없어 보이네만.","JPN":"あの子がシャドウだとしても、今すぐに撃退する必要はないように思うんだが。","ENG":"Even if she is a Shadow, I don't see why we have to eliminate her right now.","TWN":"即使那孩子是暗影，似乎也沒必要馬上就處理掉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 그게 무슨 말씀이세요?","JPN":"はい？　それはどういうことですか？","ENG":"Excuse me? What are you trying to say?","TWN":"什麼？你這話是什麼意思？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그림자 정도의 침식체는 가만히 있어도 침식파를 퍼뜨려요. 늦기 전에 어서 대처해야죠.","JPN":"シャドウほどの侵食体ならば、そこに居るだけで侵食波をまき散らしますわ。手遅れになる前に対処すべきです。","ENG":"Shadows are known to emit and spread Corruption ray! We have to get rid of them before they cause any more damage.","TWN":"暗影這類的侵蝕體，哪怕什麼都不做也會釋放侵蝕波。所以必須趁早處理掉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"치명상을 회복하려면 그림자라도 상당한 힘을 써야 한다네.","JPN":"致命傷を回復するためにはシャドウといえども相当な力が要るのだよ。","ENG":"It takes a lot of strength to recover from an injury like that. Even for a Shadow.","TWN":"要想恢復致命傷，哪怕是暗影，也必須消耗相當多的力量。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"목숨만 건졌을 뿐, 당분간은 평범한 카운터 이하라고 해야겠지.","JPN":"辛うじて死は免れたが、当分の間、力は普通のカウンター以下とみるべきだろう。","ENG":"She's alive, but barely. Right now, you can say that she is weaker than a normal Counter.","TWN":"她現在只是暫時保住了性命，所以能量在普通制裁者之下。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금도 능력을 제대로 못 쓰는 자네와 실랑이를 벌이고 있지 않나.","JPN":"現に、今も能力をまともに使えない君と口ゲンカをしているじゃないか。","ENG":"If she could fight properly, she wouldn't be having a scuffle with you, would she?","TWN":"她跟不能使用能力的你扭打在一起，不就是證明嗎。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……그렇기는 하지만요.","JPN":"……それはそうですけど。","ENG":"I guess that is true...","TWN":"……話雖如此。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"게다가 자네를 쫓아오던 그 괴물이 나타날 때를 상상해 보게.","JPN":"それに、君を追いかけてきたあの怪物が現れた場合を想像してみたまえ。","ENG":"Also, imagine that monster reappears in front of you again.","TWN":"而且，想想追你的那個怪物出現時的情形。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"위험할 때 하늘로 날아서 도망칠 수 있다는 건 굉장한 이점 아닌가?","JPN":"危ないときに空を飛んで逃げられるというのは大きなメリットではないだろうか？","ENG":"Wouldn't it be a huge advantage to be able to escape by flying?","TWN":"危險的時候可以飛到天上逃走，多我們來說也有很大的好處吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그건, 확실히…….","JPN":"それは、確かに……","ENG":"Yes... It would...","TWN":"這個，確實……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요.","JPN":"いいでしょう。","ENG":"Very well.","TWN":"好吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"말 잘했어, 장난감아! 내 편 들어 줘서 고마워!","JPN":"よく言った、オモチャ！　肩持ってくれてサンキュー！","ENG":"Good job, birdie! Thanks for taking my side!","TWN":"你說得真好，玩具！謝謝你幫我說話！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이건 장난감이 아니라 갑 버드라네. 반중력 장치에 스텔스 처리까지 한 첨단 감시 장비지.","JPN":"これはオモチャではなくて甲バードだ。反重力装置を搭載し、ステルス処理まで施された先端監視装備なんだぞ。","ENG":"I am not just a bird. I am G.A.P. Bird, a state-of-the-art surveillance machine capable of flying and stealth.","TWN":"這不是玩具，是機甲·鳥。是對反重力裝置做了隱形處理的尖端監視裝備。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"감시 장비요…? 그럼 짐승들이 다니는 길에 달아 둔 종 같은 건가요?","JPN":"監視装備……？　動物が通る道にぶら下げておくベルのようなものでしょうか？","ENG":"A surveillance machine...? You mean like those bells we install on paths that beasts take?","TWN":"監視裝備……？就像掛在野獸出沒的路上的鈴鐺一樣嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아아, 그래서였구나? 어째 학회원들이 계속 뜯어 보겠다고 난리를 치더라니.","JPN":"ああ、それでか！　学会員たちが分解するんだって妙に騒いでるなと思ったんだ。","ENG":"So that's what you were. No wonder the Society members kept wanting to open you up.","TWN":"啊啊，原來是因為這個啊？難怪學會成員們一直吵著要拆開看看呢。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일단 그냥 두고 갈 수 없는 상황이라 제 어깨를 빌려드리긴 했는데….","JPN":"一応は置いて行けない状況ですので、私の肩をお貸ししたのですが……","ENG":"I just placed it on my shoulder because I could not just leave it there...","TWN":"考慮到眼下的情況，也不能丟下你不管，所以我會暫時把肩膀借給你……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 누구죠? 학회에 감시 장비를 보낸 걸 보면 기관의 요원인가요?","JPN":"あなたは誰なのですか？　学会に監視装備を送り込んだところをみると、機関のエージェントですか？","ENG":"Who are you? Are you an agent of the Institution sent here to spy on the Society?","TWN":"你是誰？在學會放監視裝備，你是機關的人嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음. 비슷하다고 해 두지.","JPN":"うむ。似たようなものだと言っておこう。","ENG":"Hmm... Something like that.","TWN":"呃嗯，應該說差不多吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"입장상 당장 정체를 밝히기는 곤란하지만, 한 가지만은 분명히 말할 수 있다네.","JPN":"立場上、ここで正体を明らかにすることはできないが、一つだけはっきり言えることがある。","ENG":"I can't really go into detail about my identity right now, but this I can tell you.","TWN":"基於立場的問題，我不能馬上表明自己的身份，不過有一點我可以明確地告訴你。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떤 거죠?","JPN":"何でしょうか。","ENG":"And that is?","TWN":"什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 적이 아니라는 것.","JPN":"君の敵ではないということだ。","ENG":"I am not your enemy.","TWN":"我不是你的敵人。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"알겠습니다. 확인할 방도가 없으니 그 말은 당분간 보류해 두겠어요.","JPN":"わかりました。確認する手立てもありませんので、その言葉はしばらく保留ということで。","ENG":"All right. Since there is no way to confirm that right now, I will leave it at that.","TWN":"知道了。反正也沒有辦法可以確認，你說的話就姑且相信吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 고맙군.","JPN":"はは、恩に着るよ。","ENG":"Hah hah... I appreciate it.","TWN":"哈哈，謝謝。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 계속 여기서 담소를 나눌 예정인가?","JPN":"ところで、ずっとここで談笑しているつもりかい？","ENG":"But are we going to keep chit-chatting like this?","TWN":"不過我們要一直在這裡閒聊嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"서둘러야 하네. 언제 그 괴물이 다시 나타날지 미지수니 말이야.","JPN":"少し急ごう。いつあの化け物がまた現れるかは未知数だからな。","ENG":"We must hurry. We don't know when that monster will come back.","TWN":"必須抓緊時間了。那個怪物什麼時候再次出現，還是個未知數。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"맞아. 춥고 어둡고 배고파.","JPN":"賛成。寒いし暗いしお腹空いた。","ENG":"The bird's right. Plus, I'm cold and hungry.","TWN":"沒錯。又冷又黑又餓。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"1408호에 돌아가자. 학회에서 사람을 보낼지도 모르잖아. 응?","JPN":"1408号に戻ろうよ。学会から人が来るかもしれないじゃん。ね？","ENG":"Let's go back to room 1408. Who knows? Maybe the Society will send someone?","TWN":"回1408號吧。說不定學會派人來了呢，好不好？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"안 돼요. 돌아가는 길에 그 괴물과 다시 마주칠지도 모르잖아요.","JPN":"ダメです。戻る途中でまたあの怪物に出くわすかもしれませんわ。","ENG":"No. We cannot risk encountering that monster as we backtrack.","TWN":"不行。回去的路上，說不定又會遇到那個怪物。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"차라리……","JPN":"それよりは……","ENG":"However...","TWN":"還不如……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"내장기관을 비롯한 신체 어디에도 유의미한 문제는 없었습니다.","JPN":"内臓器官をはじめ、身体のどこにも問題はありませんでした。","ENG":"We examined every part of your body, including your intestines, and found no evidence of significant problems.","TWN":"包括內臟器官在內的身體所有部位，都沒有任何明顯問題。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"부학회장님의 요양을 위해 학회장님께서 의료에 관련된 아티팩트를 보내 주셨습니다.","JPN":"副学会長の療養のためにと、学会長が医療関連のアーティファクトを送ってくださいました。","ENG":"The President even sent over a medical Artifact for your recovery.","TWN":"為了讓副學會長安心休養，學會長送來了和醫療有關的人造神器。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"어떤 병이라도 치료할 수 있을 테니 걱정하지 마십시오.","JPN":"どんな病気でも治療できますので、ご安心を。","ENG":"It will allow us to treat any illness, so please don't worry.","TWN":"可以治好任何疾病，所以你不用擔心。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……아티팩트를 보내 줬다면, 제가 여기 있었다는 걸 안다는 뜻이겠죠.","JPN":"……アーティファクトを送ったということは、私がここにいることを知っていたということでしょう。","ENG":"...If Edel sent an Artifact over, that means that she knew I was there.","TWN":"……送來了人造神器的話，說明她知道我在這裡。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 에델을 만나러 가야겠습니다. 이 상황을 설명해 줄 수 있는 유일한 사람이에요.","JPN":"やはりエデルに会いにいかなければ。この状況を説明できる唯一の人物ですわ。","ENG":"I should go see her. She is the only person who can explain all of this.","TWN":"我還是得去見艾瑟兒。她是唯一能解釋這種情況的人。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시 어디 있는지 아시나요, 루나?","JPN":"どこにいるかご存じですか？　ルナさん。","ENG":"Do you know where she is right now, Luna?","TWN":"你知道她在哪裡嗎，露娜？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"당연히 모르지. 내가 그런 분이 어디서 뭐 하고 다니시는지 무슨 수로 알아?","JPN":"知るわけないでしょ。その方がどこで何をしてるのかアタシがどうやってわかるっていうの？","ENG":"Nope. Who am I to know where the President of the Society is?","TWN":"當然不知道了。我怎麼會知道她在哪，或者在做什麼？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"학회장이니까…… 맥크레디 영지에 계시는 거 아냐?","JPN":"学会長なんだから……マクレディー領地にいるんじゃない？","ENG":"But since she is the President... Shouldn't she be at the MacCready Estate?","TWN":"她是學會長……不是應該在麥克蕾蒂領地嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"예전에는 그랬죠. 하지만 최근에는 저에게 이유도 말하지 않고 외출하는 일이 잦아졌어요.","JPN":"以前はそうでしたが、最近は私に何も言わずに出かけることが多くなって。","ENG":"She used to be. But she has recently made a habit of going on trips without telling me where.","TWN":"以前是的。不過最近她經常不告訴我原因就出門。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나, 이 도시 근방에 혹시 다른 시설이 있나요?","JPN":"ルナさん、この街の近くに他の施設はありませんか？","ENG":"Luna, is there another facility close by this city?","TWN":"露娜，你知道這個城市附近還有什麼其他設施嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"다른 시설? 으음, 잠깐만……","JPN":"他の施設？　う～ん、ちょっと待って……","ENG":"Another facility? Hmm... Lemme think...","TWN":"其他設施？呃嗯，等等，我想想……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"맞다! 네가 왔던 날에 수도원이란 데에서 찾아왔어.","JPN":"そうだ！　あんたが来た日に修道院ってところから人が来てた。","ENG":"Ooh! The day you arrived, someone from a monastery visited.","TWN":"對了！你來的那天，有個人自稱是從修道院來的。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"수도원?","JPN":"修道院？","ENG":"The monastery?","TWN":"修道院？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응. 발렌티누스 수도원이라고 소개했을걸?","JPN":"うん。たしかバレンチヌス修道院って言ってたはずよ？","ENG":"Yup. It was the Valentinus Monastery if I recall correctly.","TWN":"嗯，她好像說的是聖華倫修道院？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"네가 갑자기 왜 이 먼 데까지 왔나 궁금해하더라고.","JPN":"副会長がなんで突然こんな遠いところまで来たのかって、聞いてた。","ENG":"She was asking why you were suddenly at a place so far away.","TWN":"她很想知道你為什麼突然來這麼遠的地方。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"발렌티누스…. 발렌티누스…….","JPN":"バレンチヌス……バレンチヌス……","ENG":"Valentinus... Valentinus...","TWN":"聖華倫……聖華倫……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아. 잊고 있었네요. 분명 학회의 종교학부였어요.","JPN":"ああ。思い出しましたわ。確か学会の宗教学部でした。","ENG":"Oh, I remember. That is where the Society's Religion Department is.","TWN":"啊，我給忘了。肯定是學會的宗教學院。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어디 있는지는 알고 있나요?","JPN":"どこにあるかはご存知ですか？","ENG":"Do you know where it is?","TWN":"你知道在哪裡嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"당연하지. 다른 학회원들이 알려 줬거든.","JPN":"もちろん。他の学会員が教えてくれたからね。","ENG":"Of course! The other Society members told me.","TWN":"當然知道。其他學會成員告訴過我。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 영지 바깥에는 야만스럽고 말도 안 통하는 외지인이 들끓는다고 배웠어요.","JPN":"副学会長様、領地の外には野蛮で言葉も通じない者がうようよしていると教わりました。","ENG":"Vice President, I learned that outside the estate is infested with barbaric and unintelligible outlanders.","TWN":"副學會長，我聽說領地外面到處都是野蠻又語言不通的外地人。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저희만으로 수도원까지 무사히 갈 수 있을까요?","JPN":"私たちだけで修道院まで無事にたどり着けるでしょうか？","ENG":"Do you think we can safely get to the monastery by ourselves?","TWN":"只有我們兩個，能平安地走到修道院嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"걱정 마세요, 실키. 바깥 세상이 위험하다는 건 학회가 주민들을 통제하기 편하게 심어 둔 편견입니다.","JPN":"心配いりませんよ、シルキー。外の世界が危険だというのは、学会が住民を統制しやすくするために植え付けた偏見なのです。","ENG":"No need to worry, Sylkie. The Society planted the rumor of the outside world being cruel to make it easier to control the residents.","TWN":"別擔心，思琪。外面的世界很危險，僅僅是學會為了便於控制居民們而給大家灌輸的偏見。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"한 학부의 학부장 정도라면 에델의 거취도 알 수 있겠죠.","JPN":"学部の学部長くらいでしたら、エデルの居場所についても知っているでしょう。","ENG":"But I assume that a dean of a department will know about Edel's whereabouts.","TWN":"如果是負責學院的院長，應該能知道艾瑟兒的去向。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이게 전부 어떻게 돌아가는 영문인지… 꼭 밝혀내고 말겠어요.","JPN":"ことの真相がどうなっているのか……必ず突き止めてみせますわ。","ENG":"I will make sure to get to the bottom of all of this...","TWN":"這一切究竟是怎麼回事……我一定要弄清楚。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};